from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk
import logging
import json
from datetime import datetime
import sys

# Initialize Elasticsearch client
es = Elasticsearch(
    hosts=[{'host': 'localhost', 'port': 9200}],
    timeout=30,
    max_retries=10,
    retry_on_timeout=True
)

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('search_platform.log'),
        logging.StreamHandler(sys.stdout)
    ]
)

logger = logging.getLogger(__name__)

class SearchPlatform:
    def __init__(self, index_name="logs"):
        self.index_name = index_name
        self._create_index()
    
    def _create_index(self):
        """Create index with proper mapping"""
        try:
            if not es.indices.exists(index=self.index_name):
                mapping = {
                    "mappings": {
                        "properties": {
                            "timestamp": {"type": "date"},
                            "level": {"type": "keyword"},
                            "message": {"type": "text"},
                            "service": {"type": "keyword"},
                            "host": {"type": "keyword"},
                            "tags": {"type": "keyword"}
                        }
                    }
                }
                es.indices.create(index=self.index_name, body=mapping)
                logger.info(f"Created index: {self.index_name}")
        except Exception as e:
            logger.error(f"Failed to create index: {e}")
    
    def index_document(self, document):
        """Index a single document"""
        try:
            doc = {
                "timestamp": datetime.now().isoformat(),
                "level": document.get("level", "INFO"),
                "message": document.get("message", ""),
                "service": document.get("service", "unknown"),
                "host": document.get("host", "unknown"),
                "tags": document.get("tags", [])
            }
            
            response = es.index(
                index=self.index_name,
                body=doc
            )
            logger.info(f"Indexed document with ID: {response['_id']}")
            return response
        except Exception as e:
            logger.error(f"Failed to index document: {e}")
            return None
    
    def bulk_index_documents(self, documents):
        """Bulk index multiple documents"""
        try:
            actions = []
            for doc in documents:
                action = {
                    "_index": self.index_name,
                    "_source": {
                        "timestamp": datetime.now().isoformat(),
                        "level": doc.get("level", "INFO"),
                        "message": doc.get("message", ""),
                        "service": doc.get("service", "unknown"),
                        "host": doc.get("host", "unknown"),
                        "tags": doc.get("tags", [])
                    }
                }
                actions.append(action)
            
            response = bulk(es, actions)
            logger.info(f"Bulk indexed {len(response[0])} documents")
            return response
        except Exception as e:
            logger.error(f"Failed to bulk index documents: {e}")
            return None
    
    def search(self, query, size=100, level=None):
        """Perform full-text search"""
        try:
            search_body = {
                "query": {
                    "bool": {
                        "must": [
                            {
                                "multi_match": {
                                    "query": query,
                                    "type": "best_fields",
                                    "fields": ["message", "service", "host"],
                                    "tie_breaker": 0.3,
                                    "minimum_should_match": "75%"
                                }
                            }
                        ]
                    }
                },
                "size": size,
                "sort": [
                    {"timestamp": {"order": "desc"}}
                ]
            }
            
            if level:
                search_body["query"]["bool"]["filter"] = [
                    {"term": {"level": level}}
                ]
            
            response = es.search(index=self.index_name, body=search_body)
            return response['hits']['hits']
        except Exception as e:
            logger.error(f"Search failed: {e}")
            return []
    
    def aggregate_logs(self, field, size=10):
        """Aggregate logs by field"""
        try:
            aggs_body = {
                "size": 0,
                "aggs": {
                    "field_agg": {
                        "terms": {
                            "field": field,
                            "size": size
                        }
                    }
                }
            }
            
            response = es.search(index=self.index_name, body=aggs_body)
            return response['aggregations']['field_agg']['buckets']
        except Exception as e:
            logger.error(f"Aggregation failed: {e}")
            return []
    
    def get_logs_by_service(self, service_name, size=100):
        """Get logs for specific service"""
        try:
            query = {
                "query": {
                    "term": {
                        "service": service_name
                    }
                },
                "size": size,
                "sort": [
                    {"timestamp": {"order": "desc"}}
                ]
            }
            
            response = es.search(index=self.index_name, body=query)
            return response['hits']['hits']
        except Exception as e:
            logger.error(f"Failed to get service logs: {e}")
            return []

